+                divs.push(Divergence {
+                    function: "rand",
+                    case: format!("seed={seed:#010x}, call={call_idx}"),
+                    field: "return_value",
+                    frankenlibc: format!("{fl_v}"),
+                    glibc: format!("{lc_v}"),
+                });
+                break;
+            }
+        }
+    }
+
+    assert!(
+        divs.is_empty(),
+        "rand/srand divergences:\n{}",
+        render_divs(&divs)
+    );
+}
