+    fl::srand(1);
+    let fl_one: Vec<c_int> = (0..CALLS_PER_SEED).map(|_| fl::rand()).collect();
+    assert_eq!(fl_zero, fl_one, "FrankenLibC srand(0) must match srand(1)");
